def download(
    self,
    replay_id: int,
    rate_limiter: RateLimiter | None,
    existing_hashes: set[str] | None = None,
) -> DownloadResult:
    """Download a single replay file. Does not raise — errors captured in result."""
    dest = self._output_dir / f"{replay_id}.rep"

    # Already on disk and large enough — return cached result
    if dest.exists() and dest.stat().st_size >= self._min_file_bytes:
        md5 = compute_md5(dest)
        return DownloadResult(
            replay_id=replay_id,
            success=True,
            file_path=dest,
            file_size_bytes=dest.stat().st_size,
            file_hash_md5=md5,
            error=None,
        )

    try:
        if rate_limiter is not None:
            rate_limiter.wait()
        url = download_url(replay_id)

        with self._page.expect_download(timeout=60_000) as dl_info:
            self._page.goto(url, wait_until="commit", timeout=30_000)

        dl = dl_info.value
        if dl.failure():
            return DownloadResult(
                replay_id=replay_id,
                success=False,
                file_path=None,
                file_size_bytes=0,
                file_hash_md5=None,
                error=dl.failure(),
            )

        dl.save_as(str(dest))

        if not dest.exists() or dest.stat().st_size < self._min_file_bytes:
